useHead({
    title: meta.title + ' • FlowFuse',
    meta: [{ name: 'description', content: meta.description }],
})

function scrollToAnchor(event, anchorId) {
    event.preventDefault()
    const anchor = document.getElementById(anchorId)
    if (anchor) {
        anchor.scrollIntoView({ behavior: 'smooth' })
    }
}
</script>

<template>
  <!--Hero Content-->
  <div class="nohero w-full">
    <div class="w-full pt-12 pb-20 md:pt-6 md:pb-12">
      <div class="md:flex px-6 md:my-16 items-center md:flex-row md:justify-between container mx-auto text-center md:text-left md:max-w-screen-lg gap-8 items-stretch">
        <div class="m-auto md:w-1/2">
          <h1 class="w-full mt-0 px-12 md:px-0 m-auto text-base">
            <span class="text-4xl">{{ meta.title }}</span>
          </h1>
          <p class="mb-10">
            {{ meta.description }}
          </p>
          <a
            class="ff-btn ff-btn--primary hidden min-h-[40px] md:inline"
            :href="`#${hero.buttonLink}`"
            @click="scrollToAnchor($event, hero.buttonLink)"
          >
            {{ hero.buttonText }}
          </a>
        </div>
        <div class="md:w-1/2 flex-grow relative">
          <div class="ff-image-cover ff-image-rounded w-full h-full">
            <img :src="image" :alt="imageDescription" loading="lazy" class="w-full h-auto">
            <div class="absolute top-0 right-0 flex flex-col p-4 lg:max-w-[45%] text-left">
              <div
                v-for="(stat, i) in stats"
                :key="i"
                class="bg-white/80 rounded-md px-3"
                :class="{ 'mb-2': i !== stats.length - 1 }"
              >
                <h3 v-if="stat.title" class="text-indigo-400 mt-3 font-semibold mb-0">{{ stat.title }}</h3>
                <p class="my-2 leading-5" :class="{ 'mt-0': i !== stats.length - 1 }" v-html="stat.description" />
              </div>
            </div>
          </div>
        </div>
        <a
          class="ff-btn ff-btn--primary flex flex-col w-full md:hidden m-auto mt-12"
          :href="`#${hero.buttonLink}`"
          @click="scrollToAnchor($event, hero.buttonLink)"
        >{{ hero.buttonText }}</a>
      </div>
    </div>

    <!-- The Industrial Application Platform for Plant Managers -->
    <div class="w-full">
      <div class="max-w-screen-lg mx-auto px-6">
        <h2 class="text-center w-full md:text-left text-indigo-600">{{ sectionTitle }}</h2>
        <h4 class="text-center w-full md:text-left text-gray-500 font-normal">{{ sectionSubtitle }}</h4>
        <div class="w-full grid grid-cols-1 sm:grid-cols-2 gap-8 mt-12">
          <div
            v-for="(section, i) in sections"
            :key="i"
            class="relative w-full max-md:max-w-md mx-auto bg-indigo-50 rounded-md p-6"
          >
            <div class="flex flex-row justify-center items-center gap-8 h-full">
              <div class="flex w-1/5 items-center" v-html="largeIcons[section.svg]" />
              <div class="w-4/5">
                <div class="w-full flex flex-row gap-3 mx-auto md:m-0">
                  <h4 class="w-full md:m-0 text-gray-600 font-semibold">{{ section.title }}</h4>
                </div>
                <p class="font-light mb-0" v-html="section.description" />
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
  <!--Second and third section-->
  <div class="max-w-screen-lg mx-auto mt-28 pb-12 px-6 text-lg flex flex-col md:flex-row justify-center gap-12 hover:no-underline">
    <!-- Quotes -->
    <div class="md:w-2/3 text-center text-teal-50 mb-12 text-lg flex-col flex-row items-center justify-center gap-1 hover:no-underline flex-wrap">
      <ul class="m-auto max-w-screen-lg flex flex-col gap-16">
        <li
          v-for="(quote, i) in quotes"
          :key="i"
          class="flex flex-col max-md:items-center md:flex-row gap-6 align-items-start"
        >
          <div class="w-20 h-20 min-w-20 rounded-full mx-1 bg-black p-2">
            <img :src="quote.icon" :alt="quote.alt" loading="lazy" class="w-full h-auto">
          </div>
          <div>
            <h4 class="md:text-left italic text-gray-500">&ldquo;{{ quote.quote }}&rdquo;</h4>
            <p class="md:text-right text-gray-500 text-lg">{{ quote.author }} <span class="font-bold">{{ quote.company }}</span></p>
          </div>
        </li>
      </ul>
    </div>
    <!-- Form -->
    <div id="form" class="md:w-1/3 w-full max-w-[550px] flex flex-col mx-auto">
      <div class="px-6 pb-2 max-sm:mt-4">
        <h4 class="mb-8 max-md:text-center">Download Case Study</h4>
        <HubSpotForm :form-id="hubspot.formId" />
      </div>
    </div>
  </div>
</template>
